class Solution:
    def minimumOperations(self, nums) -> int:
        d1 = d2 = d3 = 0
        for x in nums:
            if x == 1:
                d1 += 1
            elif x == 2:
                d2 = max(d1, d2) + 1
            else:
                d3 = max(d1, d2, d3) + 1
        return len(nums) - max(d1, d2, d3)

