var minimumOperations = function(nums) {
    let d1 = 0, d2 = 0, d3 = 0;
    for (const x of nums) {
        if (x === 1) {
            d1 += 1;
        } else if (x === 2) {
            d2 = Math.max(d1, d2) + 1;
        } else {
            d3 = Math.max(d1, d2, d3) + 1;
        }
    }
    return nums.length - Math.max(d1, d2, d3);
};
